# Escalation SLA tracking — compute compliance metrics

from datetime import datetime, timedelta
from dataclasses import dataclass
from typing import Literal

SLA_HOURS = {"P1": 2, "P2": 8, "P3": None}   # P3 has no response SLA (flows to ESC)

@dataclass
class EscalationEvent:
    id: str
    severity: Literal["P1", "P2", "P3"]
    submitted_at: datetime
    sponsor_response_at: datetime | None
    resolution_at: datetime | None
    status: Literal["Open", "Decided", "Escalated", "Resolved"]

    def response_hours(self) -> float | None:
        if self.sponsor_response_at is None:
            return None
        return (self.sponsor_response_at - self.submitted_at).total_seconds() / 3600

    def within_sla(self) -> bool | None:
        sla = SLA_HOURS.get(self.severity)
        if sla is None:
            return None   # P3 — no SLA
        hours = self.response_hours()
        if hours is None:
            return False  # No response yet = SLA breach
        return hours <= sla

def sla_compliance_rate(events: list[EscalationEvent], severity: str) -> float:
    relevant = [e for e in events if e.severity == severity and SLA_HOURS.get(severity)]
    if not relevant:
        return 1.0
    return sum(1 for e in relevant if e.within_sla()) / len(relevant)
